# Integrating Claude into Next.js with Streaming

Here's the simplest approach using the Anthropic SDK with Next.js App Router:

## 1. Install Dependencies

```bash
npm install @anthropic-ai/sdk
```

## 2. Create an API Route

Create `app/api/chat/route.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

export async function POST(request: Request) {
  const { messages } = await request.json();

  const stream = await client.messages.stream({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: messages,
  });

  // Convert to ReadableStream for Next.js
  const readableStream = new ReadableStream({
    async start(controller) {
      for await (const chunk of stream) {
        if (
          chunk.type === "content_block_delta" &&
          chunk.delta.type === "text_delta"
        ) {
          controller.enqueue(new TextEncoder().encode(chunk.delta.text));
        }
      }
      controller.close();
    },
  });

  return new Response(readableStream, {
    headers: { "Content-Type": "text/event-stream" },
  });
}
```

## 3. Create a Client Component

Create `app/components/ChatBox.tsx`:

```typescript
"use client";

import { useState, useRef, useEffect } from "react";

interface Message {
  role: "user" | "assistant";
  content: string;
}

export default function ChatBox() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    // Add user message
    const userMessage: Message = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [...messages, userMessage],
        }),
      });

      if (!response.body) return;

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let assistantMessage = "";

      // Add empty assistant message
      setMessages((prev) => [...prev, { role: "assistant", content: "" }]);

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value);
        assistantMessage += text;

        // Update last message with streamed content
        setMessages((prev) => [
          ...prev.slice(0, -1),
          { role: "assistant", content: assistantMessage },
        ]);
      }
    } catch (error) {
      console.error("Error:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-2xl mx-auto p-4">
      <div className="flex-1 overflow-y-auto mb-4 space-y-4">
        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`p-3 rounded-lg ${
              msg.role === "user"
                ? "bg-blue-500 text-white ml-auto max-w-xs"
                : "bg-gray-200 max-w-xs"
            }`}
          >
            {msg.content}
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask a question..."
          disabled={loading}
          className="flex-1 p-2 border rounded"
        />
        <button
          type="submit"
          disabled={loading}
          className="px-4 py-2 bg-blue-500 text-white rounded disabled:opacity-50"
        >
          Send
        </button>
      </form>
    </div>
  );
}
```

## 4. Add to Your Page

```typescript
// app/page.tsx
import ChatBox from "./components/ChatBox";

export default function Home() {
  return <ChatBox />;
}
```

## 5. Environment Setup

Create `.env.local`:

```
ANTHROPIC_API_KEY=your_api_key_here
```

## Key Features

✅ **Real-time streaming** - Responses appear word-by-word  
✅ **Conversation history** - Maintains context across messages  
✅ **Minimal setup** - ~50 lines of code  
✅ **Auto-scrolling** - Jumps to latest message  

## Optional: Add Context for User Data

If users have specific data to query:

```typescript
// Modify the client component
const handleSubmit = async (e: React.FormEvent) => {
  // ... existing code ...

  const systemPrompt = `You are an AI assistant analyzing user data. 
                        User's data: ${userDataContext}`;

  body: JSON.stringify({
    messages: [...messages, userMessage],
    system: systemPrompt,
  }),
}
```

Then update the API route to use the `system` parameter in `client.messages.stream()`.

