# Integrating Claude into Next.js for Real-Time Streaming

Here's the simplest approach for your use case:

## Quick Start: API Route + Streaming

Create a Next.js API route that streams Claude responses directly to the client:

```typescript
// app/api/chat/route.ts
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

export async function POST(request: Request) {
  const { messages } = await request.json();

  const stream = await client.messages.stream({
    model: "claude-opus-4-6-20250514",
    max_tokens: 1024,
    system: "You are a helpful assistant analyzing user data.",
    messages,
  });

  // Return ReadableStream for real-time streaming
  return new Response(stream.toReadableStream());
}
```

**Client-side (React component):**

```typescript
// components/ChatInterface.tsx
"use client";

import { useCallback, useState } from "react";

export function ChatInterface() {
  const [messages, setMessages] = useState<Array<{ role: string; content: string }>>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [streamingResponse, setStreamingResponse] = useState("");

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setIsLoading(true);
    setStreamingResponse("");

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [...messages, userMessage],
        }),
      });

      if (!response.body) throw new Error("No response body");

      const reader = response.body.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });

        // Parse Claude's SSE format
        const lines = chunk.split("\n");
        for (const line of lines) {
          if (line.startsWith("data: ")) {
            try {
              const event = JSON.parse(line.slice(6));
              if (event.type === "content_block_delta" && event.delta?.type === "text_delta") {
                setStreamingResponse((prev) => prev + event.delta.text);
              }
            } catch {
              // Ignore parse errors
            }
          }
        }
      }

      setMessages((prev) => [
        ...prev,
        { role: "assistant", content: streamingResponse },
      ]);
    } finally {
      setIsLoading(false);
      setStreamingResponse("");
    }
  }, [input, messages]);

  return (
    <div className="flex flex-col gap-4">
      <div className="flex-1 overflow-y-auto space-y-4">
        {messages.map((msg, i) => (
          <div key={i} className={`p-4 rounded ${msg.role === "user" ? "bg-blue-100" : "bg-gray-100"}`}>
            {msg.content}
          </div>
        ))}
        {streamingResponse && (
          <div className="p-4 rounded bg-gray-100 animate-pulse">
            {streamingResponse}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          disabled={isLoading}
          placeholder="Ask a question..."
          className="flex-1 px-4 py-2 border rounded"
        />
        <button
          type="submit"
          disabled={isLoading}
          className="px-4 py-2 bg-blue-500 text-white rounded disabled:opacity-50"
        >
          Send
        </button>
      </form>
    </div>
  );
}
```

